from functools import wraps
from typing import Any, Callable, Dict, List
import time
from threading import Thread

class Cache:
    def __init__(self):
        self.cache: Dict[str, Any] = {}
        self.dependencies: Dict[str, List[str]] = {}
        self.observers: Dict[str, List[Callable]] = {}
        self.ttl: Dict[str, float] = {}

    def store(self, key: str, value: Any, depends_on: List[str] = None, ttl: int = 60):
        self.cache[key] = value
        self.ttl[key] = time.time() + ttl
        if depends_on:
            self.dependencies[key] = depends_on
            for dependency in depends_on:
                if dependency not in self.observers:
                    self.observers[dependency] = []
                self.observers[dependency].append(lambda key=key: self.invalidate(key))

    def get(self, key: str):
        if key in self.cache:
            if time.time() < self.ttl[key]:
                return self.cache[key]
            else:
                self.invalidate(key)
        return None

    def invalidate(self, key: str):
        if key in self.cache:
            del self.cache[key]
            del self.ttl[key]
            if key in self.dependencies:
                del self.dependencies[key]

    def observe(self, key: str, callback: Callable):
        if key not in self.observers:
            self.observers[key] = []
        self.observers[key].append(callback)

    def notify(self, key: str):
        if key in self.observers:
            for callback in self.observers[key]:
                callback()

    def update_dependency(self, key: str):
        if key in self.observers:
            for callback in self.observers[key]:
                callback()

def cached(ttl: int = 60, depends_on: List[str] = None):
    cache = Cache()
    def decorator(func: Callable):
        @wraps(func)
        def wrapper(*args, **kwargs):
            key = f"{func.__name__}:{str(args)}:{str(kwargs)}"
            value = cache.get(key)
            if value is None:
                value = func(*args, **kwargs)
                cache.store(key, value, depends_on, ttl)
            return value
        return wrapper
    return decorator

