class Cache:
    def __init__(self):
        self.cache = {}  # Diccionario que almacena los resultados de las funciones complejas
        self.dependencias = {}  # Diccionario que almacena las dependencias asociadas a cada entrada
        self.callbacks = {}  # Diccionario que almacena los callbacks registrados para cada entrada

    def almacenar(self, clave, resultado, dependencias=None):
        """
        Almacena el resultado de una función compleja en la caché.

        :param clave: Clave única para identificar la entrada en la caché
        :param resultado: Resultado de la función compleja
        :param dependencias: Lista de dependencias asociadas a la entrada (opcional)
        """
        if clave is None or clave == "":
            raise ValueError("La clave no puede ser None o vacía")
        if resultado is None:
            raise ValueError("El resultado no puede ser None")
        if clave in self.cache:
            raise ValueError("La clave ya existe en la caché")

        self.cache[clave] = resultado
        if dependencias:
            self.dependencias[clave] = dependencias
        else:
            self.dependencias[clave] = []

    def recuperar(self, clave):
        """
        Recupera el resultado de una función compleja desde la caché.

        :param clave: Clave única para identificar la entrada en la caché
        :return: Resultado de la función compleja si existe en la caché, None en caso contrario
        """
        if clave is None or clave == "":
            raise ValueError("La clave no puede ser None o vacía")

        return self.cache.get(clave)

    def observar_cambios(self, clave, callback):
        """
        Registra un callback para observar cambios en la caché.

        :param clave: Clave única para identificar la entrada en la caché
        :param callback: Función que se ejecutará cuando se produzca un cambio en la caché
        """
        if clave is None or clave == "":
            raise ValueError("La clave no puede ser None o vacía")
        if clave not in self.callbacks:
            self.callbacks[clave] = []
        self.callbacks[clave].append(callback)

    def notificar_cambio(self, clave):
        """
        Notifica a los callbacks registrados que se ha producido un cambio en la caché.

        :param clave: Clave única para identificar la entrada en la caché
        """
        if clave in self.callbacks:
            for callback in self.callbacks[clave]:
                callback()

    def invalidar_entrada(self, clave):
        """
        Invalida una entrada en la caché.

        :param clave: Clave única para identificar la entrada en la caché
        """
        if clave in self.cache:
            del self.cache[clave]
        if clave in self.dependencias:
            del self.dependencias[clave]
        if clave in self.callbacks:
            del self.callbacks[clave]

    def actualizar_dependencia(self, dependencia):
        """
        Actualiza una dependencia en la caché.

        :param dependencia: Dependencia que se ha actualizado
        """
        if dependencia is None:
            raise ValueError("La dependencia no puede ser None")

        for clave, deps in self.dependencias.items():
            if dependencia in deps:
                self.invalidar_entrada(clave)
                self.notificar_cambio(clave)

# Ejemplo de uso
