import sqlite3
from typing import List, Dict

# Conexión a la base de datos
class Conexion:
    def __init__(self, nombre_bd: str):
        self.nombre_bd = nombre_bd
        self.conexion = sqlite3.connect(nombre_bd)
        self.cursor = self.conexion.cursor()

    def ejecutar(self, query: str, params: tuple = ()):
        try:
            self.cursor.execute(query, params)
            self.conexion.commit()
        except sqlite3.Error as e:
            print(f"Error al ejecutar la consulta: {e}")

    def consultar(self, query: str, params: tuple = ()):
        try:
            self.cursor.execute(query, params)
            return self.cursor.fetchall()
        except sqlite3.Error as e:
            print(f"Error al consultar la base de datos: {e}")
            return []

    def cerrar(self):
        self.conexion.close()

# Modelo base
class Modelo:
    def __init__(self, nombre_tabla: str, campos: List[str]):
        self.nombre_tabla = nombre_tabla
        self.campos = campos

    def crear_tabla(self, conexion: Conexion):
        query = f"CREATE TABLE IF NOT EXISTS {self.nombre_tabla} (id INTEGER PRIMARY KEY, "
        query += ", ".join([f"{campo} TEXT" for campo in self.campos])
        query += ")"
        conexion.ejecutar(query)

    def insertar(self, conexion: Conexion, datos: Dict[str, str]):
        if not datos:
            print("No se proporcionaron datos para insertar")
            return

        query = f"SELECT * FROM {self.nombre_tabla} WHERE id = ?"
        params = (datos.get("id"),)
        if conexion.consultar(query, params):
            print("El registro ya existe")
            return

        query = f"INSERT INTO {self.nombre_tabla} ({', '.join(self.campos)}) VALUES ({', '.join(['?'] * len(self.campos))})"
        params = [datos.get(campo) for campo in self.campos]
        conexion.ejecutar(query, params)

    def actualizar(self, conexion: Conexion, id: int, datos: Dict[str, str]):
        if not datos:
            print("No se proporcionaron datos para actualizar")
            return

        query = f"SELECT * FROM {self.nombre_tabla} WHERE id = ?"
        params = (id,)
        if not conexion.consultar(query, params):
            print("El registro no existe")
            return

        query = f"UPDATE {self.nombre_tabla} SET "
        query += ", ".join([f"{campo} = ?" for campo in self.campos])
        query += " WHERE id = ?"
        params = [datos.get(campo) for campo in self.campos] + [id]
        conexion.ejecutar(query, params)

    def eliminar(self, conexion: Conexion, id: int):
        query = f"SELECT * FROM {self.nombre_tabla} WHERE id = ?"
