import json
from jsonschema import validate, ValidationError
from jsonschema.exceptions import SchemaError

class CircularReferenceError(ValidationError):
    def __init__(self, message, schema, instance, path):
        super().__init__(message, schema, instance, path)

def validate_json_schema(schema, data, ignore_circular_references=False):
    """
    Valida un esquema JSON contra un conjunto de datos.

    Args:
        schema (dict): Esquema JSON a validar.
        data (dict): Datos a validar.
        ignore_circular_references (bool): Indica si se deben ignorar las referencias circulares. Por defecto, es False.

    Raises:
        ValidationError: Si el esquema no es válido o los datos no cumplen con el esquema.
        CircularReferenceError: Si se detecta una referencia circular y no se ignora.
    """
    if schema is None or data is None:
        raise ValueError("El esquema y los datos no pueden ser None")

    if not isinstance(schema, dict) or not isinstance(data, dict):
        raise ValueError("El esquema y los datos deben ser objetos JSON válidos")

    visited = set()

    def validate_recursive(instance, path, schema_path):
        if id(instance) in visited:
            if not ignore_circular_references:
                raise CircularReferenceError("Referencia circular detectada", schema, instance, path)
            return

        visited.add(id(instance))

        try:
            validate(instance, schema)
        except ValidationError as e:
            raise e

        if isinstance(instance, dict):
            for key, value in instance.items():
                if isinstance(value, dict) and "$ref" in value:
                    ref_path = value["$ref"]
                    if ref_path.startswith("#/"):
                        ref_path = ref_path[2:]
                    if ref_path == schema_path:
                        if not ignore_circular_references:
                            raise CircularReferenceError("Referencia circular detectada", schema, instance, path)
                        return
                validate_recursive(value, path + "." + key, schema_path + "." + key)

        visited.remove(id(instance))

    validate_recursive(data, "", "")

# Ejemplo de uso
schema = {
    "type": "object",
    "properties": {
        "name": {"type": "string"},
        "address": {"$ref": "#/properties/address"}  # Referencia circular
    },
    "required": ["name"]
}

data = {
    "name": "John Doe",
    "address": {
        "street": "123 Main St",
        "city": "Anytown",
        "state": "CA",
        "zip": "12345"
    }
}

try:
    validate_json_schema(schema, data)
except CircularReferenceError as e:
    print(f"Error: {e}")
except ValidationError as e:
    print(f"Error de validación: {e}")
