        try:
            hash(clave)
        except TypeError:
            raise ValueError("Los argumentos pasados no son hashables")

        if clave in self.cache:
            return self.cache[clave]
        else:
            try:
                resultado = funcion(*args, **kwargs)
                self.cache[clave] = resultado
                self.dependencias[clave] = set()
                return resultado
            except Exception as e:
                raise ValueError("La función pasada lanzó una excepción") from e

    def registrar_dependencia(self, clave, dependencia):
        if clave in self.dependencias:
            self.dependencias[clave].add(dependencia)

    def invalidar_cache(self, clave):
        if clave in self.cache:
            del self.cache[clave]
            if clave in self.dependencias:
                for dependencia in self.dependencias[clave]:
                    if dependencia in self.cache:
                        del self.cache[dependencia]
                del self.dependencias[clave]

