class RetryMechanism:
    def __init__(self, max_retries, initial_backoff, backoff_factor):
        if max_retries <= 0:
            raise ValueError("El número máximo de reintentos debe ser mayor que cero")
        self.max_retries = max_retries
        self.initial_backoff = initial_backoff
        self.backoff_factor = backoff_factor
        self.retries = 0

    def retry(self, func):
        if not callable(func):
            raise ValueError("La función debe ser callable")
        while self.retries < self.max_retries:
            result = func()
            if result is not None:
                return result
            self.retries += 1
            backoff = self.initial_backoff * (self.backoff_factor ** self.retries)
            time.sleep(backoff + random.uniform(0, 1))
        return None

class CircuitBreaker:
    def __init__(self, threshold, timeout):
        if threshold <= 0:
            raise ValueError("El umbral de fallos debe ser mayor que cero")
        self.threshold = threshold
        self.timeout = timeout
        self.failures = 0
        self.circuit_open = False
        self.opened_at = None

    def is_circuit_open(self):
        return self.circuit_open

    def reset(self):
        self.failures = 0
        self.circuit_open = False
        self.opened_at = None

    def update(self, success):
        if not isinstance(success, bool):
            raise ValueError("El parámetro success debe ser un booleano")
        if success:
