import sys
import heapq

def dijkstra(grafo, inicio):
    """
    Calcula las distancias mínimas desde el vértice de inicio a todos los demás vértices en el grafo.

    Args:
        grafo (dict): Grafo ponderado representado como un diccionario de diccionarios.
        inicio (str): Vértice de inicio.

    Returns:
        dict: Distancias mínimas desde el vértice de inicio a todos los demás vértices.

    Raises:
        ValueError: Si el grafo está vacío o el vértice de inicio no existe en el grafo.
    """
    if not grafo:
        raise ValueError("El grafo está vacío")
    if inicio not in grafo:
        raise ValueError("El vértice de inicio no existe en el grafo")

    distancias = {vertice: sys.maxsize for vertice in grafo}
    distancias[inicio] = 0
    pq = [(0, inicio)]

    while pq:
        distancia_actual, vertice_actual = heapq.heappop(pq)
        if distancia_actual > distancias[vertice_actual]:
            continue
        for vecino, peso in grafo[vertice_actual].items():
            distancia_nueva = distancia_actual + peso
            if distancia_nueva < distancias[vecino]:
                distancias[vecino] = distancia_nueva
                heapq.heappush(pq, (distancia_nueva, vecino))

    return distancias

def detectar_ciclos_negativos(grafo):
    """
    Detecta si el grafo contiene ciclos negativos.

    Args:
        grafo (dict): Grafo ponderado representado como un diccionario de diccionarios.

    Returns:
        bool: True si el grafo contiene ciclos negativos, False de lo contrario.

    Raises:
        ValueError: Si el grafo está vacío.
    """
    if not grafo:
        raise ValueError("El grafo está vacío")

    distancias = {vertice: 0 for vertice in grafo}

    for _ in range(len(grafo) - 1):
        for vertice in grafo:
            for vecino, peso in grafo[vertice].items():
                distancias[vecino] = min(distancias[vecino], distancias[vertice] + peso)

    for vertice in grafo:
        for vecino, peso in grafo[vertice].items():
            if distancias[vecino] > distancias[vertice] + peso:
                return True

    return False

