import json
from jsonschema import validate, ValidationError, RefResolver
from urllib.parse import urljoin, urlparse

class CircularReferenceValidator:
    """
    Validador de JSON Schema que maneja referencias circulares dentro de los esquemas.

    Atributos:
    - schema (dict): El esquema JSON a validar.
    - base_uri (str): La URI base para resolver referencias relativas.
    - visited (set): Un conjunto para rastrear los esquemas visitados y detectar referencias circulares.
    """

    def __init__(self, schema, base_uri=''):
        """
        Inicializa el validador con el esquema y la URI base.

        Args:
        - schema (dict): El esquema JSON a validar.
        - base_uri (str): La URI base para resolver referencias relativas.
        """
        self.schema = schema
        self.base_uri = base_uri
        self.visited = set()

    def validate(self, instance):
        """
        Valida la instancia contra el esquema.

        Args:
        - instance (dict): La instancia JSON a validar.

        Raises:
        - ValidationError: Si la instancia no es válida según el esquema.
        """
        try:
            self._validate(instance, self.schema)
        except ValidationError as e:
            raise ValidationError(f"Error de validación: {e}") from e

    def _validate(self, instance, schema):
        """
        Valida la instancia contra el esquema de forma recursiva.

        Args:
        - instance (dict): La instancia JSON a validar.
        - schema (dict): El esquema JSON a validar contra.

        Raises:
        - ValidationError: Si la instancia no es válida según el esquema.
        """
        if id(schema) in self.visited:
            raise ValidationError("Referencia circular detectada")
        self.visited.add(id(schema))

        if '$ref' in schema:
            ref = schema['$ref']
            if not ref.startswith('#'):
                ref = urljoin(self.base_uri, ref)
            parsed_ref = urlparse(ref)
            if parsed_ref.fragment:
                ref_schema = self._resolve_ref(parsed_ref.fragment, self.schema)
                if ref_schema:
                    self._validate(instance, ref_schema)
                else:
                    raise ValidationError("Referencia no resuelta")
            else:
                raise ValidationError("Referencia no válida")
        else:
            try:
                validate(instance, schema)
            except ValidationError as e:
                raise ValidationError(f"Error de validación: {e}") from e

        self.visited.remove(id(schema))

    def _resolve_ref(self, ref, schema):
        """
        Resuelve una referencia dentro del esquema.

        Args:
        - ref (str): La referencia a resolver.
        - schema (dict): El esquema JSON que contiene la referencia.

        Returns:
        - dict: El esquema resuelto si la referencia es válida, None de lo contrario.
        """
        if ref.startswith('/'):
            ref = ref[1:]
        parts = ref.split('/')
        current_schema = schema
        for part in parts:
            if part in current_schema:
                current_schema = current_schema[part]
            else:
                return None
        return current_schema

