import json
from jsonschema import validate, ValidationError
import networkx as nx

class JSONSchemaValidator:
    def __init__(self, schema):
        """
        Inicializa el validador con un esquema JSON.

        :param schema: El esquema JSON a validar.
        """
        if schema is None or not isinstance(schema, dict):
            raise ValueError("El esquema debe ser un diccionario no vacío")

        self.schema = schema
        self.references = {}
        self._build_reference_dict()

    def validate(self, data):
        """
        Valida los datos contra el esquema.

        :param data: Los datos a validar.
        """
        try:
            validate(instance=data, schema=self.schema)
        except ValidationError as e:
            print(f"Error de validación: {e}")

    def _build_reference_dict(self):
        """
        Construye un diccionario de referencias para evitar búsqueda lineal.
        """
        for key, value in self.schema.items():
            if isinstance(value, dict) and "$ref" in value:
                ref = value["$ref"]
                if ref not in self.references:
                    self.references[ref] = self._resolve_reference(ref)

    def _resolve_reference(self, reference):
        """
        Resuelve una referencia en el esquema.

        :param reference: La referencia a resolver.
        :return: El valor de la referencia resuelta.
        """
        if reference in self.references:
            return self.references[reference]
        else:
            for key, value in self.schema.items():
                if isinstance(value, dict) and "$ref" in value and value["$ref"] == reference:
                    self.references[reference] = value
                    return value
            raise ValueError(f"Referencia no encontrada: {reference}")

    def _detect_circular_references(self):
        """
        Detecta referencias circulares en el esquema.

        :return: True si se detecta una referencia circular, False de lo contrario.
        """
        G = nx.DiGraph()
        for key, value in self.schema.items():
            if isinstance(value, dict) and "$ref" in value:
                ref = value["$ref"]
                G.add_edge(ref, self._resolve_reference(ref))

        try:
            cycle = nx.find_cycle(G)
            print("Se detectó una referencia circular")
            return True
        except nx.NetworkXNoCycle:
            print("No se detectaron referencias circulares")
            return False

