def tokenize(expresion):
    """
    Tokeniza la expresión en números, operadores y paréntesis.

    :param expresion: La expresión matemática a tokenizar.
    :return: Una lista de tokens.
    """
    tokens = []
    numero = ""
    for caracter in expresion:
        if caracter.isspace():
            continue
        if caracter.isdigit() or caracter == "." or caracter == "e" or caracter == "E" or caracter == "+" or caracter == "-":
            numero += caracter
        else:
            if numero:
                tokens.append(numero)
                numero = ""
            if caracter in "+-*/()":
                tokens.append(caracter)
    if numero:
        tokens.append(numero)
    return tokens

# Conversión a notación postfix (RPN)
def infix_to_rpn(tokens):
    """
    Convierte la expresión de notación infija a notación postfix (RPN) utilizando el algoritmo de Shunting Yard.

    :param tokens: La lista de tokens obtenida de la tokenización.
    :return: La expresión en notación postfix (RPN).
    """
    operadores = []
    rpn = []
    precedencia = {"+": 1, "-": 1, "*": 2, "/": 2}
    for token in tokens:
        if token.replace('.', '', 1).replace('e', '', 1).replace('E', '', 1).replace('+', '', 1).replace('-', '', 1).isdigit():
            rpn.append(token)
        elif token in "+-*/":
            while (operadores and operadores[-1] in "+-*/" and precedencia[operadores[-1]] >= precedencia[token]):
                rpn.append(operadores.pop())
            operadores.append(token)
        elif token == "(":
            operadores.append(token)
        elif token == ")":
            while operadores and operadores[-1] != "(":
                rpn.append(operadores.pop())
            if not operadores or operadores[-1] != "(":
                raise ValueError("Paréntesis no balanceados")
            operadores.pop()
    while operadores:
        if operadores[-1] == "(":
            raise ValueError("Paréntesis no balanceados")
        rpn.append(operadores.pop())
    return rpn

# Evaluación de la expresión en notación postfix (RPN)
def evaluar_rpn(rpn):
    """
    Evalúa la expresión en notación postfix (RPN) utilizando una pila.

    :param rpn: La expresión en notación postfix (RPN).
    :return: El resultado numérico de la expresión.
    """
    pila = []
    for token in rpn:
        if token.replace('.', '', 1).replace('e', '', 1).replace('E', '', 1).replace('+', '', 1).replace('-', '', 1).isdigit():
            pila.append(float(token))
        else:
            if len(pila) < 2:
                raise ValueError("Expresión inválida")
            operando2 = pila.pop()
            operando1 = pila.pop()
            if token == "+":
                resultado = operando1 + operando2
            elif token == "-":
                resultado = operando1 - operando2
            elif token == "*":
                resultado = operando1 * operando2
            elif token == "/":
                if operando2 == 0:
                    raise ZeroDivisionError("División por cero")
                resultado = operando1 / operando2
            pila.append(resultado)
    if len(pila) != 1:
        raise ValueError("Expresión inválida")
    return pila[0]

def parser(expresion):
    try:
        tokens = tokenize(expresion)
        rpn = infix_to_rpn(tokens)
        resultado = evaluar_rpn(rpn)
        return resultado
    except Exception as e:
        return str(e)

