import pickle

class Cache:
    def __init__(self):
        self.cache = {}
        self.dependencias = {}

    def registrar_dependencia(self, nombre, funcion):
        if nombre not in self.dependencias:
            self.dependencias[nombre] = funcion

    def obtener_hash(self, args, kwargs):
        args_str = pickle.dumps(args)
        kwargs_str = pickle.dumps(kwargs)
        return hashlib.md5(args_str + kwargs_str).hexdigest()

    def obtener_resultado(self, nombre, args, kwargs):
        hash_args = self.obtener_hash(args, kwargs)
        if nombre in self.cache and hash_args in self.cache[nombre]:
            return self.cache[nombre][hash_args]
        else:
            resultado = self.dependencias[nombre](*args, **kwargs)
            self.almacenar_resultado(nombre, args, kwargs, resultado)
            return resultado

    def almacenar_resultado(self, nombre, args, kwargs, resultado):
        hash_args = self.obtener_hash(args, kwargs)
        if nombre not in self.cache:
            self.cache[nombre] = {}
        self.cache[nombre][hash_args] = resultado

    def invalidar_cache(self, nombre):
        if nombre in self.cache:
            self.cache[nombre] = {}

def cache(func):
    cache_instancia = Cache()
    cache_instancia.registrar_dependencia(func.__name__, func)

    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        resultado = cache_instancia.obtener_resultado(func.__name__, args, kwargs)
        return resultado

    def registrar_dependencia(nombre, funcion):
        cache_instancia.registrar_dependencia(nombre, funcion)

    def invalidar_cache(nombre):
        cache_instancia.invalidar_cache(nombre)

    wrapper.registrar_dependencia = registrar_dependencia
    wrapper.invalidar_cache = invalidar_cache
    return wrapper

