def groupby(ordenada, clave):
    """
    Agrupa los elementos consecutivos en una lista ordenada según el valor de la clave.

    Args:
        ordenada (list): Lista ordenada de elementos.
        clave (function): Función que devuelve el valor de la clave para cada elemento.

    Yields:
        tuple: Tupla que contiene el valor de la clave y un generador de elementos que pertenecen a ese grupo.
    """
    if not callable(clave):
        raise TypeError("La función clave debe ser callable")

    if not ordenada:
        return

    actual = clave(ordenada[0])
    grupo = [ordenada[0]]

    for elemento in ordenada[1:]:
        try:
            clave_elemento = clave(elemento)
        except TypeError:
            raise TypeError("La función clave no es aplicable a todos los elementos")

        if clave_elemento == actual:
            grupo.append(elemento)
        else:
            yield actual, (x for x in grupo)
            actual = clave_elemento
            grupo = [elemento]

    yield actual, (x for x in grupo)


