import unittest

class TestGroupby(unittest.TestCase):
    def test_grupo_vacio(self):
        self.assertEqual(list(groupby([], lambda x: x)), [])

    def test_grupo_un_elemento(self):
        resultado = list(groupby([1], lambda x: x))
        self.assertEqual(resultado, [(1, [1])])

    def test_grupo_consecutivos(self):
        resultado = list(groupby([1, 1, 2, 2, 3, 3], lambda x: x))
        self.assertEqual(resultado, [(1, [1, 1]), (2, [2, 2]), (3, [3, 3])])

    def test_grupo_no_consecutivos(self):
        resultado = list(groupby([1, 2, 1, 2, 1, 2], lambda x: x))
        self.assertEqual(resultado, [(1, [1]), (2, [2]), (1, [1]), (2, [2]), (1, [1]), (2, [2])])

    def test_grupo_con_funcion_clave(self):
        resultado = list(groupby([1, 2, 3, 4, 5, 6], lambda x: x % 2))
        self.assertEqual(resultado, [(1, [1]), (0, [2]), (1, [3]), (0, [4]), (1, [5]), (0, [6])])

    def test_grupo_con_datos_no_numericos(self):
        resultado = list(groupby(['a', 'a', 'b', 'b', 'c', 'c'], lambda x: x))
        self.assertEqual(resultado, [('a', ['a', 'a']), ('b', ['b', 'b']), ('c', ['c', 'c'])])

