import functools

class Cache:
    def __init__(self):
        self.cache = {}
        self.dependencies = {}

    def register_function(self, func):
        @functools.wraps(func)
        def wrapper(*args):
            key = (func.__name__, args)
            if key in self.cache:
                return self.cache[key]
            else:
                result = func(*args)
                self.cache[key] = result
                return result
        self.dependencies[func.__name__] = []
        return wrapper

    def add_dependency(self, func_name, dependency):
        self.dependencies[func_name].append(dependency.__name__)

    def invalidate(self, func_name):
        for key in list(self.cache.keys()):
            if func_name in self.dependencies.get(key[0], []):
                del self.cache[key]

    def get(self, func, *args):
        key = (func.__name__, args)
        if key in self.cache:
            return self.cache[key]
        else:
            result = func(*args)
            self.cache[key] = result
            return result

