from heapq import heapify, heappop, heappush

class RateLimitExceeded(Exception):
    """Excepción personalizada para cuando se excede el límite de solicitudes"""
    pass

class RateLimiter:
    def __init__(self):
        self.users = defaultdict(lambda: defaultdict(lambda: []))

    def add_request(self, user_id, limit, period):
        """Agrega una solicitud para el usuario y límite dados"""
        if user_id is None or limit is None:
            raise ValueError("user_id y limit no pueden ser None")

        current_time = time.time()
        queue = self.users[user_id][limit]

        # Elimina las solicitudes expiradas
        queue = [timestamp for timestamp in queue if current_time - timestamp <= period]
        self.users[user_id][limit] = queue

        # Agrega la nueva solicitud
        queue.append(current_time)
        self.users[user_id][limit] = queue

    def is_allowed(self, user_id, limit, max_requests, period):
        """Verifica si se permite una nueva solicitud para el usuario y límite dados"""
        if user_id is None or limit is None:
            raise ValueError("user_id y limit no pueden ser None")

        queue = self.users[user_id][limit]

        # Elimina las solicitudes expiradas
        queue = [timestamp for timestamp in queue if time.time() - timestamp <= period]
        self.users[user_id][limit] = queue

        return len(queue) < max_requests

    def get_remaining_requests(self, user_id, limit, max_requests, period):
        """Obtiene el número de solicitudes restantes para el usuario y límite dados"""
        if user_id is None or limit is None:
            raise ValueError("user_id y limit no pueden ser None")

        queue = self.users[user_id][limit]

        # Elimina las solicitudes expiradas
        queue = [timestamp for timestamp in queue if time.time() - timestamp <= period]
        self.users[user_id][limit] = queue

        return max_requests - len(queue)

class DynamicRateLimiter:
    def __init__(self):
        self.rate_limiter = RateLimiter()
        self.users = defaultdict(lambda: defaultdict(lambda: 0))

    def add_request(self, user_id, limit, max_requests, period):
        """Agrega una solicitud para el usuario y límite dados"""
        if user_id is None or limit is None:
            raise ValueError("user_id y limit no pueden ser None")

        if max_requests <= 0:
            raise ValueError("max_requests debe ser mayor que 0")

        if period <= 0:
            raise ValueError("period debe ser mayor que 0")

        self.rate_limiter.add_request(user_id, limit, period)

        if not self.rate_limiter.is_allowed(user_id, limit, max_requests, period):
            raise RateLimitExceeded("Límite de solicitudes alcanzado")

        self.users[user_id][limit] += 1

    def get_remaining_requests(self, user_id, limit, max_requests, period):
        """Obtiene el número de solicitudes restantes para el usuario y límite dados"""
        return self.rate_limiter.get_remaining_requests(user_id, limit, max_requests, period)

    def adapt_limit(self, user_id, limit, new_max_requests):
        """Ajusta el límite de solicitudes para el usuario y límite dados"""
        if user_id is None or limit is None:
            raise ValueError("user_id y limit no pueden ser None")

        if new_max_requests <= 0:
            raise ValueError("new_max_requests debe ser mayor que 0")

        self.users[user_id][limit] = new_max_requests

