        Inicializa el validador con un esquema.

        :param schema: Esquema JSON para validar.
        """
        self.schema = schema
        self.circular_references = set()

    def validate(self, json_data):
        """
        Valida el JSON contra el esquema.

        :param json_data: JSON a validar.
        :return: True si es válido, False de lo contrario.
        """
        try:
            jsonschema.validate(instance=json_data, schema=self.schema, format_checker=FormatChecker())
        except ValidationError as e:
            print(f"Error de validación: {e}")
            return False

        # Buscar referencias circulares
        self.find_circular_references(self.schema, json_data)
        return True

    def find_circular_references(self, schema, json_data):
        """
        Busca referencias circulares en el esquema.

        :param schema: Esquema a buscar.
        :param json_data: JSON asociado.
        """
        if id(schema) in self.circular_references:
            print("Referencia circular detectada. Se sugiere romper el ciclo.")
            return

        self.circular_references.add(id(schema))

        if "$ref" in schema:
            ref = schema["$ref"]
            if ref.startswith("#/"):
                # Referencia interna
                self.find_circular_references(self.schema, json_data)
            else:
                # Referencia externa
                print("Referencia externa detectada. Se sugiere revisar la estructura del esquema.")

        if "properties" in schema:
            for prop in schema["properties"].values():
                self.find_circular_references(prop, json_data)

        if "items" in schema:
            self.find_circular_references(schema["items"], json_data)

        self.circular_references.remove(id(schema))

