                if self.is_valid(key):
                    return self.cache[key]
            result = func(*args, **kwargs)
            self.cache[key] = result
            self.update_dependencies(func, args, kwargs)
            return result
        return wrapper

    def generate_key(self, func, args, kwargs):
        func_hash = self.get_function_hash(func)
        args_hash = self.get_args_hash(args, kwargs)
        return f"{func_hash}:{args_hash}"

    def get_function_hash(self, func):
        if func not in self.function_hashes:
            self.function_hashes[func] = hashlib.sha256(pickle.dumps(func.__code__)).hexdigest()
        return self.function_hashes[func]

    def get_args_hash(self, args, kwargs):
        try:
            return hashlib.sha256(pickle.dumps((args, kwargs))).hexdigest()
        except TypeError:
            # Si los argumentos no son hashables, creamos un hash basado en su representación como strings
            args_str = [str(arg) for arg in args]
            kwargs_str = [f"{key}={value}" for key, value in kwargs.items()]
            return hashlib.sha256(pickle.dumps((",".join(args_str + kwargs_str)))).hexdigest()

    def is_valid(self, key):
        func_hash, _ = key.split(":")
        if func_hash not in self.dependencies:
            return True  # Si no hay dependencias, la entrada es válida
        for dependency in self.dependencies.get(func_hash, []):
            if dependency not in self.cache:
                return False
        return True

    def update_dependencies(self, func, args, kwargs):
        func_hash = self.get_function_hash(func)
        dependencies = []
        for arg in args:
            if callable(arg):
                dependencies.append(self.get_function_hash(arg))
        for kwarg in kwargs.values():
            if callable(kwarg):
                dependencies.append(self.get_function_hash(kwarg))
        self.dependencies[func_hash] = dependencies
        for dependency in dependencies:
            if dependency in self.cache:
                # No eliminamos la entrada de la caché para la dependencia,
                # solo actualizamos la lista de dependencias
                pass

    def invalidate(self, func):
        func_hash = self.get_function_hash(func)
        for key in list(self.cache.keys()):
            if key.startswith(f"{func_hash}:"):
                del self.cache[key]
        if func_hash in self.dependencies:
            del self.dependencies[func_hash]

def complex_function(a, b):
    time.sleep(2)  # Simulación de una función compleja
    return a + b

def otra_funcion(x):
    time.sleep(1)  # Simulación de otra función compleja
    return x * 2

cache = Cache()
complex_function_cached = cache.register_function(complex_function)
otra_funcion_cached = cache.register_function(otra_funcion)

print(complex_function_cached(2, 3))  # Llama a la función y almacena el resultado en la caché
print(complex_function_cached(2, 3))  # Obtiene el resultado de la caché
print(otra_funcion_cached(5))  # Llama a la función y almacena el resultado en la caché
print(otra_funcion_cached(5))  # Obtiene el resultado de la caché
