def dijkstra(grafo, inicio, fin):
    """
    Implementación del algoritmo de Dijkstra para encontrar la ruta más corta en un grafo ponderado.

    Args:
    grafo (dict): Grafo ponderado representado como un diccionario de adyacencia.
    inicio (str): Nodo de inicio.
    fin (str): Nodo de fin.

    Returns:
    tuple: Ruta más corta y distancia, o mensaje de error si no es posible encontrar una ruta válida.
    """

    # Validación de entradas
    if not grafo:
        return "Error: Grafo vacío"
    if inicio not in grafo or fin not in grafo:
        return "Error: Nodo de inicio o fin no encontrado en el grafo"
    if inicio == fin:
        return "Error: Nodo de inicio y fin son el mismo"

    # Inicialización de distancias y padres
    distancias = {nodo: float('inf') for nodo in grafo}
    distancias[inicio] = 0
    padres = {nodo: None for nodo in grafo}

    # Detección de ciclos negativos
    for nodo in grafo:
        for vecino, peso in grafo[nodo].items():
            if peso < 0:
                return "Error: Grafo contiene ciclos negativos"

    # Algoritmo de Dijkstra
    cola_prioridad = [(0, inicio)]
    while cola_prioridad:
        distancia_actual, nodo_actual = heapq.heappop(cola_prioridad)
        if distancia_actual > distancias[nodo_actual]:
            continue
        for vecino, peso in grafo[nodo_actual].items():
            distancia_nueva = distancia_actual + peso
            if distancia_nueva < distancias[vecino]:
                distancias[vecino] = distancia_nueva
                padres[vecino] = nodo_actual
                heapq.heappush(cola_prioridad, (distancia_nueva, vecino))

    # Construcción de la ruta más corta
    ruta = []
    nodo_actual = fin
    while nodo_actual is not None:
        ruta.append(nodo_actual)
        nodo_actual = padres[nodo_actual]
    ruta.reverse()

    # Verificación de ruta válida
    if distancias[fin] == float('inf'):
        return "No es posible encontrar una ruta válida"

    return ruta, distancias[fin]

