    if not grafo[fin]:
        raise ValueError("El nodo de fin no tiene aristas")

    for nodo, aristas in grafo.items():
        for vecino, peso in aristas.items():
            if not isinstance(peso, (int, float)) or peso < 0:
                raise ValueError("El peso de la arista debe ser un número no negativo")

