import sys
import heapq

def dijkstra_algorithm(graph, start_vertex):
    """
    Implementación del algoritmo de Dijkstra para encontrar las distancias más cortas desde un vértice de inicio a todos los demás vértices en un grafo ponderado.

    Args:
        graph (dict): Grafo representado como un diccionario de adjacencia.
        start_vertex (str): Vértice de inicio.

    Returns:
        dict: Diccionario con las distancias más cortas desde el vértice de inicio a todos los demás vértices.
    """
    if not graph:
        raise ValueError("El grafo está vacío")

    if start_vertex not in graph:
        raise ValueError("El vértice de inicio no existe en el grafo")

    distances = {vertex: float('inf') for vertex in graph}
    distances[start_vertex] = 0

    priority_queue = [(0, start_vertex)]

    while priority_queue:
        current_distance, current_vertex = heapq.heappop(priority_queue)

        if current_distance > distances[current_vertex]:
            continue

        for neighbor, weight in graph[current_vertex].items():
            distance = current_distance + weight

            if distance < distances[neighbor]:
                distances[neighbor] = distance
                heapq.heappush(priority_queue, (distance, neighbor))

    return distances

def detect_negative_cycles(graph):
    """
    Función para detectar la presencia de ciclos negativos en un grafo ponderado.

    Args:
        graph (dict): Grafo representado como un diccionario de adjacencia.

    Returns:
        bool: True si el grafo contiene un ciclo negativo, False en caso contrario.
    """
    if not graph:
        raise ValueError("El grafo está vacío")

    distances = {vertex: float('inf') for vertex in graph}
    distances[next(iter(graph))] = 0

    for _ in range(len(graph) - 1):
        for vertex in graph:
            for neighbor, weight in graph[vertex].items():
                if distances[vertex] + weight < distances[neighbor]:
                    distances[neighbor] = distances[vertex] + weight

    for vertex in graph:
        for neighbor, weight in graph[vertex].items():
            if distances[vertex] + weight < distances[neighbor]:
                return True

    return False

def main():
    graph = {
        'A': {'B': -1, 'C': 4},
        'B': {'C': 3, 'D': 2, 'E': 2},
        'C': {},
        'D': {'B': 1, 'C': 5},
        'E': {'D': -3}
    }

    if detect_negative_cycles(graph):
        print("El grafo contiene un ciclo negativo")
    else:
        start_vertex = 'A'
        distances = dijkstra_algorithm(graph, start_vertex)
        print("Distancias más cortas desde", start_vertex)
        for vertex, distance in distances.items():
            print(vertex, ":", distance)

if __name__ == "__main__":
