import functools
import threading
from collections import defaultdict, OrderedDict

class Cache:
    def __init__(self):
        self.cache = OrderedDict()
        self.dependencias = defaultdict(list)
        self.lock = threading.Lock()

    def get(self, clave):
        with self.lock:
            if clave in self.cache:
                return self.cache[clave]
            else:
                return None

    def set(self, clave, valor):
        with self.lock:
            self.cache[clave] = valor
            self.dependencias[clave] = []

    def delete(self, clave):
        with self.lock:
            if clave in self.cache:
                del self.cache[clave]
                del self.dependencias[clave]
                self.invalidar_dependencias(clave)

    def agregar_dependencia(self, clave, dependencia):
        with self.lock:
            self.dependencias[clave].append(dependencia)

    def invalidar_dependencias(self, clave):
        with self.lock:
            for dependencia in self.dependencias[clave]:
                self.delete(dependencia)

    def __len__(self):
        return len(self.cache)

    def __contains__(self, clave):
        return clave in self.cache

def cache(maxsize=128):
    cache_instancia = Cache()

    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            clave = str(args) + str(kwargs)
            valor = cache_instancia.get(clave)
            if valor is None:
                try:
                    valor = func(*args, **kwargs)
                    cache_instancia.set(clave, valor)
                except Exception as e:
                    print(f"Error al calcular {clave}: {e}")
                    return None
            return valor

        def set_dependencia(clave, dependencia):
            cache_instancia.agregar_dependencia(clave, dependencia)

        def delete_dependencia(clave):
            cache_instancia.delete(clave)

        wrapper.set_dependencia = set_dependencia
        wrapper.delete_dependencia = delete_dependencia
        return wrapper

    return decorator

# Ejemplo de uso
