from threading import Lock

class RateLimiter:
    def __init__(self):
        self.buckets = defaultdict(lambda: deque())
        self.locks = defaultdict(Lock)
        self.rates = {}
        self.metrics = defaultdict(lambda: {"requests": 0, "time": 0})
        self.window_size = 60  # Ventana deslizante en segundos

    def add_user(self, user_id, rate):
        if rate <= 0:
            raise ValueError("La tasa de límite debe ser mayor que cero")
        self.rates[user_id] = rate
        self.buckets[user_id] = deque()
        self.locks[user_id] = Lock()
        self.metrics[user_id] = {"requests": 0, "time": 0}

    def remove_user(self, user_id):
        if user_id in self.rates:
            del self.rates[user_id]
            if user_id in self.buckets:
                del self.buckets[user_id]
            if user_id in self.locks:
                del self.locks[user_id]
            if user_id in self.metrics:
                del self.metrics[user_id]

    def is_allowed(self, user_id):
        if user_id not in self.rates:
            return False
        rate = self.rates[user_id]
        with self.locks[user_id]:
            current_time = time.time()
            bucket = self.buckets[user_id]
            # Eliminar solicitudes antiguas
            while bucket and bucket[0][0] < current_time - self.window_size:
                bucket.popleft()
            # Verificar si se ha alcanzado el límite
            if len(bucket) >= rate:
                return False
            # Agregar solicitud actual
            bucket.append((current_time,))
            # Actualizar métricas
            self.metrics[user_id]["requests"] += 1
            self.metrics[user_id]["time"] = current_time
            return True

    def get_metrics(self, user_id):
        if user_id in self.metrics:
            return self.metrics[user_id]
        else:
            return None

def main():
