            raise ValueError("El factor de backoff exponencial debe ser mayor o igual que 1")

        self.max_retries = max_retries
        self.timeout = timeout
        self.backoff_factor = backoff_factor
        self.state = "cerrado"  # Estado inicial: cerrado
        self.failure_count = 0  # Contador de fallos
        self.last_failure = 0  # Tiempo del último fallo
        self.next_retry = 0  # Tiempo del próximo reintento

    def __call__(self, func):
        """
        Decorador para aplicar el circuito breaker a una función.

        :param func: Función a proteger con el circuito breaker.
        :return: Función decorada con el circuito breaker.
        """
        def wrapper(*args, **kwargs):
            if self.state == "abierto":
                # Si el circuito está abierto, no permitir llamadas
                if time.time() - self.last_failure > self.timeout:
                    # Si ha pasado el tiempo de inactividad, cerrar el circuito
                    self.state = "cerrado"
                    self.failure_count = 0
                else:
                    # Si no ha pasado el tiempo de inactividad, aplicar backoff
                    if time.time() < self.next_retry:
                        logging.info("Demasiado pronto para reintentaar")
                        raise Exception("Demasiado pronto para reintentaar")
                    else:
                        # Reintentar la llamada
                        self.next_retry = time.time() + (2 ** self.failure_count) * self.backoff_factor
                        try:
                            return func(*args, **kwargs)
                        except Exception as e:
                            # Si la llamada falla, incrementar el contador de fallos
                            self.failure_count += 1
                            self.last_failure = time.time()
                            if self.failure_count >= self.max_retries:
                                # Si se alcanza el número máximo de reintentos, abrir el circuito
                                self.state = "abierto"
                            raise e
            else:
                # Si el circuito está cerrado, permitir la llamada
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    # Si la llamada falla, abrir el circuito
                    self.state = "abierto"
                    self.failure_count = 1
                    self.last_failure = time.time()
                    self.next_retry = time.time() + self.backoff_factor
                    raise e

        return wrapper

