class JSONSchemaValidator:
    def __init__(self, schema: Dict[str, Any]):
        self.schema = schema
        self.visited = set()

    def validate(self, data: Any) -> bool:
        try:
            self._validate(data, self.schema)
            return True
        except ValueError as e:
            print(f"Error de validación: {e}")
            return False

    def _validate(self, data: Any, schema: Dict[str, Any]) -> None:
        if id(schema) in self.visited:
            raise ValueError("Referencia circular detectada en el esquema")
        self.visited.add(id(schema))

        if schema.get("type") is None:
            raise ValueError("El esquema debe tener un tipo")

        if schema.get("type") == "object":
            if not isinstance(data, dict):
                raise ValueError("El dato no es un objeto")
            for prop, prop_schema in schema.get("properties", {}).items():
                if prop in data:
                    self._validate(data[prop], prop_schema)
                elif "required" in schema and prop in schema["required"]:
                    raise ValueError(f"La propiedad '{prop}' es requerida")
        elif schema.get("type") == "array":
            if not isinstance(data, list):
                raise ValueError("El dato no es una lista")
            for item in data:
                self._validate(item, schema.get("items", {}))
        elif schema.get("type") == "string":
            if not isinstance(data, str):
                raise ValueError("El dato no es una cadena")
        elif schema.get("type") == "integer":
            if not isinstance(data, int):
                raise ValueError("El dato no es un entero")
        elif schema.get("type") == "boolean":
            if not isinstance(data, bool):
                raise ValueError("El dato no es un booleano")
        elif schema.get("type") == "null":
            if data is not None:
                raise ValueError("El dato no es nulo")
        else:
            raise ValueError(f"Tipo de esquema desconocido: {schema.get('type')}")

        self.visited.remove(id(schema))

def validar_json_contra_esquema(data: Any, schema: Dict[str, Any]) -> bool:
    if schema is None or data is None:
        raise ValueError("El esquema y el dato no pueden ser None")
    validator = JSONSchemaValidator(schema)
    return validator.validate(data)

