        """
        Valida el JSON contra el esquema y detecta referencias circulares.

        Args:
            json_data (dict): Datos JSON a validar.
            schema (dict): Esquema JSON a utilizar para la validación.

        Raises:
            ValueError: Si se detecta una referencia circular o si el JSON no es válido según el esquema.
        """
        if json_data is None or schema is None:
            raise ValueError("Los datos JSON y el esquema no pueden ser None")

        try:
            jsonschema.validate(instance=json_data, schema=schema, format_checker=FormatChecker())
        except ValidationError as e:
            raise ValueError(f"Error de validación: {e}")

        self.visited_schemas.clear()
        if self.has_circular_references(schema):
            raise ValueError("El esquema contiene referencias circulares")

    def has_circular_references(self, schema):
        """
        Detecta referencias circulares en el esquema.

        Args:
            schema (dict): Esquema JSON a analizar.

        Returns:
            bool: True si se detecta una referencia circular, False de lo contrario.
        """
        if schema is None:
            return False

        if id(schema) in self.visited_schemas:
            return True

        self.visited_schemas.add(id(schema))

        if "$ref" in schema:
            ref = schema["$ref"]
            if ref.startswith("#"):
                # Referencia interna, buscar en el esquema actual
                for key, value in schema.items():
                    if key != "$ref" and isinstance(value, dict):
