class Invalidador:
    def __init__(self):
        self.cache = {}
        self.dependencias = {}
        self.importancia = {}

    def registrar_funcion(self, funcion, dependencias, importancia):
        """
        Registra una función en el sistema de caché con sus dependencias e importancia.

        Args:
            funcion (callable): La función a registrar.
            dependencias (list): Lista de dependencias de la función.
            importancia (dict): Diccionario con la importancia de cada dependencia.
        """
        if not callable(funcion):
            raise ValueError("La función debe ser callable")
        if not isinstance(dependencias, list) or not all(isinstance(dep, str) for dep in dependencias):
            raise ValueError("Las dependencias deben ser una lista de strings")
        if not isinstance(importancia, dict) or not all(isinstance(key, str) and isinstance(value, int) for key, value in importancia.items()):
            raise ValueError("La importancia debe ser un diccionario con strings como claves y enteros como valores")

        self.dependencias[funcion] = dependencias
        self.importancia[funcion] = importancia

    def invalidar(self, funcion):
        """
        Invalida la entrada del caché para una función específica.

        Args:
            funcion (callable): La función para la que se invalidará el caché.
        """
        if funcion in self.cache:
            del self.cache[funcion]

    def obtener_resultado(self, funcion, *args, **kwargs):
        """
        Obtiene el resultado de una función, utilizando el caché si es posible.

        Args:
            funcion (callable): La función para la que se obtendrá el resultado.
            *args: Argumentos posicionales para la función.
            **kwargs: Argumentos nominales para la función.

        Returns:
            El resultado de la función.
        """
        if funcion in self.cache:
            return self.cache[funcion]
        else:
            resultado = funcion(*args, **kwargs)
            self.cache[funcion] = resultado
            return resultado

    def actualizar_dependencia(self, dependencia):
        """
        Actualiza una dependencia en el sistema de caché, invalidando las entradas relevantes.

        Args:
            dependencia (str): La dependencia que se actualizará.
        """
        for funcion, deps in self.dependencias.items():
            if dependencia in deps:
                self.invalidar(funcion)

def funcion_compleja(invalidador):
    def decorador(funcion):
        @wraps(funcion)
        def wrapper(*args, **kwargs):
            return invalidador.obtener_resultado(funcion, *args, **kwargs)
        return wrapper
    return decorador

