class Lexer:
    def __init__(self, texto: str):
        self.texto = texto
        self.posicion = 0
        self.tokens: List[Token] = []

    def tokenize(self) -> List[Token]:
        while self.posicion < len(self.texto):
            if self.texto[self.posicion].isspace():
                self.posicion += 1
                continue

            if self.texto[self.posicion].isdigit() or self.texto[self.posicion] == '.':
                self.tokens.append(self._tokenizar_numero())
                continue

            if self.texto[self.posicion] in '+-*/':
                self.tokens.append(Token(TokenTipo.OPERADOR, self.texto[self.posicion]))
                self.posicion += 1
                continue

            if self.texto[self.posicion] in '()':
                self.tokens.append(Token(TokenTipo.PARENTECIS, self.texto[self.posicion]))
                self.posicion += 1
                continue

            raise SyntaxError(f'Caracter no reconocido en la posición {self.posicion}: {self.texto[self.posicion]}')

        return self.tokens

    def _tokenizar_numero(self) -> Token:
        match = re.match(r'\d+(?:\.\d+)?', self.texto[self.posicion:])
        if match:
            numero = match.group()
            self.posicion += len(numero)
            return Token(TokenTipo.NUMERO, numero)
        else:
            raise SyntaxError(f'Error al tokenizar número en la posición {self.posicion}')

