        if not self.tokens:
            raise SyntaxError('Expresión vacía')

        return self._parsear_expresion()

    def _parsear_expresion(self) -> float:
        resultado = self._parsear_termino()
        while self.posicion < len(self.tokens) and self.tokens[self.posicion].tipo == TokenTipo.OPERADOR and self.tokens[self.posicion].valor in '+-':
            operador = self.tokens[self.posicion].valor
            self.posicion += 1
            termino = self._parsear_termino()
            if operador == '+':
                resultado += termino
            else:
                resultado -= termino
        return resultado

    def _parsear_termino(self) -> float:
        resultado = self._parsear_factor()
        while self.posicion < len(self.tokens) and self.tokens[self.posicion].tipo == TokenTipo.OPERADOR and self.tokens[self.posicion].valor in '*/':
            operador = self.tokens[self.posicion].valor
            self.posicion += 1
            factor = self._parsear_factor()
            if operador == '*':
                resultado *= factor
            else:
                resultado /= factor
        return resultado

    def _parsear_factor(self) -> float:
        if self.tokens[self.posicion].tipo == TokenTipo.NUMERO:
            resultado = float(self.tokens[self.posicion].valor)
            self.posicion += 1
            return resultado
        elif self.tokens[self.posicion].tipo == TokenTipo.PARENTECIS and self.tokens[self.posicion].valor == '(':
            self.posicion += 1
            resultado = self._parsear_expresion()
            if self.posicion >= len(self.tokens) or self.tokens[self.posicion].tipo != TokenTipo.PARENTECIS or self.tokens[self.posicion].valor != ')':
                raise SyntaxError('Paréntesis no balanceados')
