from dataclasses import dataclass
from enum import Enum
from heapq import heappop, heappush

class Prioridad(Enum):
    """Enum para representar la prioridad de los eventos"""
    ALTA = 3
    MEDIA = 2
    BAJA = 1

@dataclass
class Evento:
    """Clase para representar un evento"""
    tipo: str
    datos: Dict[str, str]
    prioridad: Prioridad

class SistemaEventos:
    """Clase para implementar el sistema de eventos pub/sub"""
    def __init__(self):
        """Inicializa el sistema de eventos"""
        self.suscriptores: Dict[str, List[Callable]] = {}
        self.filtros: Dict[Callable, List[Callable]] = {}

    def publicar(self, evento: Evento):
        """Publica un evento a los suscriptores correspondientes"""
        if evento.tipo in self.suscriptores:
            for suscriptor in self.suscriptores[evento.tipo]:
                suscriptor(evento)

    def suscribir(self, tipo: str, callback: Callable, prioridad: Prioridad = Prioridad.MEDIA):
        """Suscribe un callback a un tipo de evento con una prioridad específica"""
        if tipo not in self.suscriptores:
            self.suscriptores[tipo] = []
        if callback not in self.suscriptores[tipo]:
            self.suscriptores[tipo].append(callback)

    def desuscribir(self, tipo: str, callback: Callable):
        """Desuscribe un callback de un tipo de evento"""
        if tipo in self.suscriptores and callback in self.suscriptores[tipo]:
            self.suscriptores[tipo].remove(callback)

    def filtrar(self, callback: Callable, tipo: str, prioridad: Prioridad = Prioridad.MEDIA):
        """Filtra los eventos para un callback específico"""
        def filtro(evento: Evento):
            if evento.tipo == tipo and evento.prioridad == prioridad:
                callback(evento)
        self.filtros[callback] = [filtro]

    def entregar(self, eventos: List[Evento]):
        """Entrega los eventos a los suscriptores en orden de prioridad"""
        cola_prioridad: List[tuple] = []
        for evento in eventos:
            heappush(cola_prioridad, (-evento.prioridad.value, evento))
        while cola_prioridad:
            _, evento = heappop(cola_prioridad)
            self.publicar(evento)

def callback_alta(evento: Evento):
    """Callback para eventos de alta prioridad"""
    print(f"Evento ALTO: {evento.tipo} - {evento.datos}")

def callback_media(evento: Evento):
