import heapq
from typing import Callable, Dict, List, Tuple
import logging

# Configuración de logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class Evento:
    """Representa un evento con un tipo, datos y prioridad."""
    def __init__(self, tipo: str, datos: Dict, prioridad: int):
        if prioridad < 0:
            raise ValueError("La prioridad no puede ser negativa")
        self.tipo = tipo
        self.datos = datos
        self.prioridad = prioridad

    def __lt__(self, otro: 'Evento'):
        return self.prioridad < otro.prioridad

class Suscriptor:
    """Representa un suscriptor con un callback, un filtro de tipo y un nivel de prioridad mínimo."""
    def __init__(self, callback: Callable, filtro_tipo: str = None, prioridad_minima: int = 0):
        if not callable(callback):
            raise ValueError("El callback debe ser una función")
        if prioridad_minima < 0:
            raise ValueError("La prioridad mínima no puede ser negativa")
        self.callback = callback
        self.filtro_tipo = filtro_tipo
        self.prioridad_minima = prioridad_minima

class MotorEventos:
    """Motor del sistema de eventos pub/sub."""
    def __init__(self):
        self.suscriptores: Dict[str, List[Suscriptor]] = {}
        self.eventos: List[Evento] = []

    def publicar(self, evento: Evento):
        """Publica un evento en el sistema."""
        if evento.tipo not in self.suscriptores:
            logger.warning(f"No hay suscriptores para el tema {evento.tipo}")
        heapq.heappush(self.eventos, evento)
        self.entregar_eventos()

    def suscribir(self, tema: str, suscriptor: Suscriptor):
        """Suscribe un tema con un filtro específico y nivel de prioridad."""
        if tema not in self.suscriptores:
            self.suscriptores[tema] = []
        self.suscriptores[tema].append(suscriptor)

    def entregar_eventos(self):
        """Entrega los eventos a los suscriptores en orden de prioridad, aplicando los filtros correspondientes."""
        while self.eventos:
            evento = heapq.heappop(self.eventos)
            for suscriptor in self.suscriptores.get(evento.tipo, []):
                if (suscriptor.filtro_tipo is None or suscriptor.filtro_tipo == evento.tipo) and evento.prioridad >= suscriptor.prioridad_minima:
                    suscriptor.callback(evento.datos)

# Ejemplo de uso
