        """Registra una dependencia entre dos claves de caché."""
        if clave not in self.dependencias:
            self.dependencias[clave] = []
        self.dependencias[clave].append(depende_de)

    def invalidar_cache(self, clave: str):
        """Invalida la caché para una clave específica y sus dependientes."""
        if self.lock:
            return  # Evita recursividad infinita
        self.lock = True
        if clave in self.cache:
            del self.cache[clave]
        for clave_dependiente, dependencias in self.dependencias.items():
            if clave in dependencias:
                self.invalidar_cache(clave_dependiente)
        self.lock = False

    def obtener_valor(self, clave: str):
        """Obtiene el valor almacenado en la caché para una clave específica."""
        return self.cache.get(clave)

    def almacenar_valor(self, clave: str, valor: Any):
        """Almacena un valor en la caché para una clave específica."""
        self.cache[clave] = valor

def generar_clave(args, kwargs):
    """Genera una clave de caché única para una función y sus argumentos."""
    args_str = str(args)
    kwargs_str = str(kwargs)
    return md5((args_str + kwargs_str).encode()).hexdigest()

def cache(func):
    """Decorador que implementa la lógica de caché."""
    cache_instancia = Cache()

    @wraps(func)
    def wrapper(*args, **kwargs):
        try:
            clave = generar_clave(args, kwargs)
            if cache_instancia.obtener_valor(clave) is not None:
                return cache_instancia.obtener_valor(clave)
            else:
