        self.id = id
        self.usada = False

    def ejecutar_query(self, query: str) -> str:
        # Simulación de ejecución de query
        time.sleep(1)
        return f"Resultado de la query {query} en la conexión {self.id}"

class PoolDeConexiones:
    def __init__(self, max_conexiones: int, timeout: float):
        if max_conexiones <= 0:
            raise ValueError("El número máximo de conexiones debe ser mayor que 0")
        if timeout < 0:
            raise ValueError("El timeout no puede ser negativo")

        self.max_conexiones = max_conexiones
        self.timeout = timeout
        self.conexiones = queue.Queue(max_conexiones)
        self.cerrado = False
        self.lock = threading.Lock()
        self.condicion = threading.Condition(self.lock)

        for i in range(max_conexiones):
            self.conexiones.put(Conexion(i))

    def obtener_conexion(self) -> Optional[Conexion]:
        if self.cerrado:
            return None

        with self.condicion:
            while not self.conexiones.empty() and not self.cerrado:
                try:
                    return self.conexiones.get(timeout=self.timeout)
                except queue.Empty:
                    pass

            # Si el pool está vacío y no se ha cerrado, esperamos a que una conexión esté disponible
            while not self.conexiones.empty() and not self.cerrado:
                self.condicion.wait(self.timeout)

            if self.cerrado:
                return None

            try:
                return self.conexiones.get(timeout=self.timeout)
            except queue.Empty:
                return None

