        with self.lock:
            if not self.conexiones.full():
                self.conexiones.put(conexion)
                with self.condicion:
                    self.condicion.notify_all()

    def cerrar(self):
        self.cerrado = True
        with self.lock:
            while not self.conexiones.empty():
                conexion = self.conexiones.get()
                # Simulación de cierre de conexión
                print(f"Cerrando conexión {conexion.id}")

