    def __init__(self, conexion: Connection):
        self.conexion = conexion
        self.cursor: Cursor = conexion.cursor()
        self.modelos: Dict[str, Modelo] = {}

    def registrar_modelo(self, modelo: Modelo):
        if modelo.nombre in self.modelos:
            raise Error(f"El modelo {modelo.nombre} ya existe en el ORM")
        self.modelos[modelo.nombre] = modelo

    def crear_tabla(self, modelo: Modelo):
        if not modelo.atributos:
            raise Error(f"El modelo {modelo.nombre} no tiene atributos")
        query = f"CREATE TABLE IF NOT EXISTS {modelo.nombre} ("
        for atributo in modelo.atributos:
            if atributo.tipo == TipoAtributo.ENTERO:
                query += f"{atributo.nombre} INTEGER, "
            elif atributo.tipo == TipoAtributo.TEXTO:
                query += f"{atributo.nombre} TEXT, "
            elif atributo.tipo == TipoAtributo.FECHA:
                query += f"{atributo.nombre} DATE, "
