from typing import Dict, Any

class ValidadorJSONSchema:
    def __init__(self, schema: Dict[str, Any]):
        self.schema = schema
        self.visitados = set()

    def validar(self, instancia: Dict[str, Any]) -> None:
        try:
            validate(instance=instancia, schema=self.schema, format_checker=None)
        except ValidationError as e:
            raise ValueError(f"Error de validación: {e}")

    def _validar(self, instancia: Dict[str, Any], schema: Dict[str, Any]) -> None:
        if id(schema) in self.visitados:
            raise ValueError("Referencia circular detectada en el esquema")
        self.visitados.add(id(schema))

        if "$ref" in schema:
            ref = schema["$ref"]
            if ref.startswith("#/"):
                ruta = ref.split("/")[1:]
                schema_referenciado = self._obtener_esquema_referenciado(self.schema, ruta)
                if schema_referenciado is None:
                    raise ValueError(f"Referencia no resuelta: {ref}")
                self._validar(instancia, schema_referenciado)
            else:
                raise ValueError(f"Referencia externa no soportada: {ref}")

        if "properties" in schema:
            for propiedad, schema_propiedad in schema["properties"].items():
                if propiedad in instancia:
                    self._validar(instancia[propiedad], schema_propiedad)

        if "items" in schema:
            for item in instancia:
                self._validar(item, schema["items"])

        self.visitados.remove(id(schema))

    def _obtener_esquema_referenciado(self, schema: Dict[str, Any], ruta: list[str]) -> Dict[str, Any]:
        if not ruta:
            return schema
        if ruta[0] not in schema:
            return None
        return self._obtener_esquema_referenciado(schema[ruta[0]], ruta[1:])

def main():
