    """
    Clase para validar esquemas JSON y detectar referencias circulares.
    """

    def __init__(self, schema):
        """
        Inicializa el validador con un esquema JSON.

        :param schema: Esquema JSON a validar.
        """
        self.schema = schema
        self.circulares = set()

    def validar(self, datos):
        """
        Valida los datos proporcionados contra el esquema.

        :param datos: Datos a validar.
        :raises ValueError: Si se detecta una referencia circular en el esquema.
        :raises ValidationError: Si los datos no cumplen con el esquema.
        """
        try:
            jsonschema.validate(instance=datos, schema=self.schema, format_checker=FormatChecker())
        except ValidationError as e:
            if self._es_referencia_circular(e):
                raise ValueError("Se detectó una referencia circular en el esquema")
            else:
                raise e

    def _es_referencia_circular(self, error):
        """
        Verifica si el error se debe a una referencia circular en el esquema.

        :param error: Error de validación.
        :return: True si el error se debe a una referencia circular, False de lo contrario.
        """
        if error.schema.get("$ref"):
            ref = error.schema["$ref"]
            if ref in self.circulares:
                return True
            self.circulares.add(ref)
            try:
                # Validar contra un esquema mínimo que cumpla con las propiedades obligatorias
                min_schema = self._get_min_schema(self.schema)
                jsonschema.validate(instance={}, schema=min_schema, format_checker=FormatChecker())
            except ValidationError as e:
                if self._es_referencia_circular(e):
                    return True
            return False
        return False

    def _get_min_schema(self, schema):
        """
        Obtiene un esquema mínimo que cumpla con las propiedades obligatorias.

        :param schema: Esquema original.
        :return: Esquema mínimo.
        """
        min_schema = {}
        for prop, value in schema.get("properties", {}).items():
            if value.get("required"):
                min_schema[prop] = value
        return min_schema

    def _es_referencia_valida(self, ref):
        """
        Verifica si la referencia es válida y apunta a una definición existente en el esquema.

        :param ref: Referencia a verificar.
