    def __init__(self):
        self.suscriptores: Dict[str, List[Callable]] = {}
        self.filtros: Dict[str, List[Callable]] = {}
        self.prioridades: Dict[str, List[Prioridad]] = {}
        self.cola_eventos = Queue()
        self.lock = threading.Lock()

    def publicar(self, evento: Evento):
        with self.lock:
            if evento.tipo not in self.suscriptores:
                print(f"Advertencia: No hay suscriptores para el tipo de evento '{evento.tipo}'")
            self.cola_eventos.put(evento)

    def procesar_eventos(self):
        while True:
            try:
                evento = self.cola_eventos.get(timeout=1)
            except Exception as e:
                continue
            self.notificar_suscriptores(evento)

    def suscribirse(self, tipo: str, callback: Callable, filtro: Callable = None, prioridad: Prioridad = Prioridad.BAJA):
        if not callable(callback):
            raise ValueError("El callback debe ser una función")
        if filtro is not None and not callable(filtro):
            raise ValueError("El filtro debe ser una función o None")
        if not isinstance(prioridad, Prioridad):
            raise ValueError("La prioridad debe ser un valor de la enumeración Prioridad")

        with self.lock:
            if tipo not in self.suscriptores:
                self.suscriptores[tipo] = []
                self.filtros[tipo] = []
                self.prioridades[tipo] = []
            self.suscriptores[tipo].append(callback)
            self.filtros[tipo].append(filtro)
            self.prioridades[tipo].append(prioridad)

    def notificar_suscriptores(self, evento: Evento):
        with self.lock:
            if evento.tipo not in self.suscriptores:
                print(f"Advertencia: No hay suscriptores para el tipo de evento '{evento.tipo}'")
                return
            suscriptores_ordenados = sorted(zip(self.suscriptores[evento.tipo], self.filtros[evento.tipo], self.prioridades[evento.tipo]), key=lambda x: x[2].value, reverse=True)
            for callback, filtro, _ in suscriptores_ordenados:
                if filtro is None or filtro(evento):
                    callback(evento)

