import threading
from queue import Queue, PriorityQueue
from typing import List

class Evento:
    def __init__(self, tipo: str, mensaje: str, prioridad: int):
        self.tipo = tipo
        self.mensaje = mensaje
        self.prioridad = prioridad

    def __repr__(self):
        return f"Evento(tipo='{self.tipo}', mensaje='{self.mensaje}', prioridad={self.prioridad})"


class Filtro:
    def __init__(self, tipo: str, condicion: str):
        self.tipo = tipo
        self.condicion = condicion

    def __repr__(self):
        return f"Filtro(tipo='{self.tipo}', condicion='{self.condicion}')"


class Suscriptor:
    def __init__(self, nombre: str, filtro: Filtro, prioridad: int):
        self.nombre = nombre
        self.filtro = filtro
        self.prioridad = prioridad

    def __repr__(self):
        return f"Suscriptor(nombre='{self.nombre}', filtro={self.filtro}, prioridad={self.prioridad})"


class Publicador:
    def __init__(self):
        self.suscriptores: List[Suscriptor] = []
        self.colas: dict = {}

    def suscribir(self, suscriptor: Suscriptor):
        if suscriptor.nombre not in [s.nombre for s in self.suscriptores]:
            self.suscriptores.append(suscriptor)
            self.colas[suscriptor.nombre] = PriorityQueue()
        else:
            raise ValueError("Nombre de suscriptor ya en uso")

    def desuscribir(self, nombre: str):
        for suscriptor in self.suscriptores:
            if suscriptor.nombre == nombre:
                self.suscriptores.remove(suscriptor)
                del self.colas[nombre]
                return
        raise ValueError("Suscriptor no encontrado")

    def publicar(self, evento: Evento):
        for suscriptor in self.suscriptores:
            if self._filtrar(evento, suscriptor.filtro):
                self.colas[suscriptor.nombre].put((suscriptor.prioridad, evento))

    def _filtrar(self, evento: Evento, filtro: Filtro):
        if filtro.tipo == 'tipo':
            return evento.tipo == filtro.condicion
        elif filtro.tipo == 'mensaje':
            return evento.mensaje == filtro.condicion
        else:
            return False

    def entregar(self, suscriptor: Suscriptor):
        while True:
            prioridad, evento = self.colas[suscriptor.nombre].get()
            print(f"Entregado a {suscriptor.nombre}: {evento.mensaje}")
            self.colas[suscriptor.nombre].task_done()

    def obtener_suscriptores(self):
        return self.suscriptores

    def obtener_cola(self, nombre: str):
        return self.colas[nombre]


# Uso
