from jsonschema import validate, ValidationError, FormatChecker
from jsonschema.validators import Draft7Validator
from urllib.parse import urljoin, urlparse
import json

class CircularReferenceValidator(Draft7Validator):
    def __init__(self, schema, types=None):
        super().__init__(schema, types=types)
        self.seen = set()

    def is_valid(self, instance):
        try:
            self.validate(instance)
            return True
        except ValidationError:
            return False

    def validate(self, instance, schema=None, cls=None, *args, **kwargs):
        if schema is None:
            schema = self.schema
        schema_id = id(schema)
        if schema_id in self.seen:
            return
        self.seen.add(schema_id)
        try:
            super().validate(instance, schema, *args, **kwargs)
        finally:
            self.seen.remove(schema_id)

def validate_json_schema(instance, schema):
    """
    Valida un JSON contra un esquema JSON Schema.

    Args:
        instance (dict): El JSON a validar.
        schema (dict): El esquema JSON Schema.

    Returns:
        bool: True si el JSON es válido, False de lo contrario.
    """
    if instance is None or schema is None:
        return False

    validator = CircularReferenceValidator(schema)
    return validator.is_valid(instance)

