from typing import List, Dict
from dataclasses import dataclass

@dataclass
class Entidad:
    id: int
    nombre: str

class BaseDeDatosSimulada:
    def __init__(self):
        self.tablas: Dict[str, List[Entidad]] = {}
        self.indices: Dict[str, Dict[int, Entidad]] = {}

    def crear_tabla(self, nombre_tabla: str):
        if not nombre_tabla:
            raise ValueError("Nombre de tabla no puede ser vacío o nulo")
        if nombre_tabla not in self.tablas:
            self.tablas[nombre_tabla] = []
            self.indices[nombre_tabla] = {}

    def insertar(self, nombre_tabla: str, entidad: Entidad):
        if not isinstance(entidad, Entidad):
            raise ValueError("Entidad no es una instancia de Entidad")
        if entidad.id < 0:
            raise ValueError("ID de entidad no puede ser negativo")
        if nombre_tabla in self.tablas:
            if entidad.id in self.indices[nombre_tabla]:
                raise ValueError("Entidad con ID ya existe en la tabla")
            self.tablas[nombre_tabla].append(entidad)
            self.indices[nombre_tabla][entidad.id] = entidad
        else:
            raise ValueError("Tabla no existe en la base de datos")

    def consultar(self, nombre_tabla: str, id_entidad: int) -> Entidad:
        if not nombre_tabla:
            raise ValueError("Nombre de tabla no puede ser vacío o nulo")
        if id_entidad < 0:
            raise ValueError("ID de entidad no puede ser negativo")
        if nombre_tabla in self.tablas:
            if id_entidad in self.indices[nombre_tabla]:
                return self.indices[nombre_tabla][id_entidad]
            else:
                raise ValueError("Entidad con ID no existe en la tabla")
        else:
            raise ValueError("Tabla no existe en la base de datos")

class MiniORM:
    def __init__(self, base_de_datos: BaseDeDatosSimulada):
        self.base_de_datos = base_de_datos

    def mapear(self, clase_entidad: type, nombre_tabla: str):
        if not issubclass(clase_entidad, Entidad):
            raise ValueError("Clase de entidad no hereda de Entidad")
        self.base_de_datos.crear_tabla(nombre_tabla)

    def guardar(self, entidad: Entidad):
        nombre_tabla = type(entidad).__name__.lower() + 's'
        self.base_de_datos.insertar(nombre_tabla, entidad)

    def consultar_por_id(self, clase_entidad: type, id_entidad: int) -> Entidad:
        nombre_tabla = clase_entidad.__name__.lower() + 's'
        return self.base_de_datos.consultar(nombre_tabla, id_entidad)

class Cliente(Entidad):
    def __init__(self, id: int, nombre: str):
        super().__init__(id, nombre)

class Pedido(Entidad):
    def __init__(self, id: int, nombre: str, cliente_id: int):
        super().__init__(id, nombre)
        self.cliente_id = cliente_id

def main():
    base_de_datos = BaseDeDatosSimulada()
    orm = MiniORM(base_de_datos)
    orm.mapear(Cliente, 'clientes')
    orm.mapear(Pedido, 'pedidos')
    cliente1 = Cliente(1, 'Juan')
    cliente2 = Cliente(2, 'Maria')
    orm.guardar(cliente1)
    orm.guardar(cliente2)
    pedido1 = Pedido(1, 'Pedido 1', 1)
    pedido2 = Pedido(2, 'Pedido 2', 1)
    pedido3 = Pedido(3, 'Pedido 3', 2)
    orm.guardar(pedido1)
    orm.guardar(pedido2)
    orm.guardar(pedido3)
    cliente_recuperado = orm.consultar_por_id(Cliente, 1)
    print(f'Cliente recuperado: {cliente_recuperado.nombre}')
    pedidos_recuperados = [pedido for pedido in base_de_datos.tablas['pedidos'] if pedido.cliente_id == 1]
    print('Pedidos del cliente 1:')
    for pedido in pedidos_recuperados:
        print(pedido.nombre)

if __name__ == '__main__':
    main()
